cat > src/utils/hashiLogic.js <<'EOF'
const ERR_NON_ADJ = 'Cannot connect non-adjacent islands';
const ERR_MAX_PAIR = 'Max 2 bridges per pair';
const ERR_EXCEED = 'Island would exceed its number';
const ERR_CROSS = 'Bridges would cross';

function keyFor(a, b) {
  const p1 = { x: a.x, y: a.y };
  const p2 = { x: b.x, y: b.y };
  const first = (p1.x < p2.x) || (p1.x === p2.x && p1.y <= p2.y) ? p1 : p2;
  const second = first === p1 ? p2 : p1;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

function parseKey(k) {
  const [x1, y1, x2, y2] = k.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function isAxisAligned(a, b) {
  return a.x === b.x || a.y === b.y;
}

function between(v, a, b) {
  return v > Math.min(a, b) && v < Math.max(a, b);
}

function hasIslandBetween(islands, a, b) {
  if (a.x === b.x) {
    return islands.some((i) => i.id !== a.id && i.id !== b.id && i.x === a.x && between(i.y, a.y, b.y));
  }
  if (a.y === b.y) {
    return islands.some((i) => i.id !== a.id && i.id !== b.id && i.y === a.y && between(i.x, a.x, b.x));
  }
  return true;
}

function segmentsCross(segA, segB) {
  const a = segA;
  const b = segB;
  const aVert = a.x1 === a.x2;
  const bVert = b.x1 === b.x2;
  if (aVert === bVert) return false;

  const v = aVert ? a : b;
  const h = aVert ? b : a;

  const ix = v.x1;
  const iy = h.y1;

  const vMinY = Math.min(v.y1, v.y2);
  const vMaxY = Math.max(v.y1, v.y2);
  const hMinX = Math.min(h.x1, h.x2);
  const hMaxX = Math.max(h.x1, h.x2);

  const intersects = ix > hMinX && ix < hMaxX && iy > vMinY && iy < vMaxY;
  return intersects;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(k);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }
  return counts;
}

function anyCrossing(bridges) {
  const segs = [];
  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(k);
    segs.push({ x1, y1, x2, y2 });
  }
  for (let i = 0; i < segs.length; i++) {
    for (let j = i + 1; j < segs.length; j++) {
      const a = segs[i];
      const b = segs[j];
      const shareEndpoint =
        (a.x1 === b.x1 && a.y1 === b.y1) ||
        (a.x1 === b.x2 && a.y1 === b.y2) ||
        (a.x2 === b.x1 && a.y2 === b.y1) ||
        (a.x2 === b.x2 && a.y2 === b.y2);
      if (shareEndpoint) continue;
      if (segmentsCross(a, b)) return true;
    }
  }
  return false;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!from || !to) return { valid: false, error: ERR_NON_ADJ };
  if (from.id === to.id) return { valid: false, error: ERR_NON_ADJ };
  if (!isAxisAligned(from, to)) return { valid: false, error: ERR_NON_ADJ };
  if (hasIslandBetween(islands, from, to)) return { valid: false, error: ERR_NON_ADJ };

  const k = keyFor(from, to);
  const current = bridges.get(k) ?? 0;
  const next = current + delta;
  if (next < 0) return { valid: false, error: ERR_MAX_PAIR };
  if (next > 2) return { valid: false, error: ERR_MAX_PAIR };

  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) ?? 0;
  const toCount = counts.get(to.id) ?? 0;
  if (fromCount + delta > from.value || toCount + delta > to.value) {
    return { valid: false, error: ERR_EXCEED };
  }

  const tmp = new Map(bridges);
  if (next === 0) tmp.delete(k);
  else tmp.set(k, next);
  if (anyCrossing(tmp)) return { valid: false, error: ERR_CROSS };

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  const byCoord = new Map();
  for (const i of islands) byCoord.set(`${i.x},${i.y}`, i);

  const adj = new Map();
  for (const i of islands) adj.set(i.id, []);

  for (const [k, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(k);
    const a = byCoord.get(`${x1},${y1}`);
    const b = byCoord.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const startId = islands[0].id;
  const seen = new Set([startId]);
  const stack = [startId];
  while (stack.length) {
    const cur = stack.pop();
    for (const nb of adj.get(cur) ?? []) {
      if (!seen.has(nb)) {
        seen.add(nb);
        stack.push(nb);
      }
    }
  }

  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }
  if (anyCrossing(bridges)) return false;
  if (!checkConnectivity(islands, bridges)) return false;
  return true;
}

export const ERROR_TEXTS = {
  ERR_NON_ADJ,
  ERR_MAX_PAIR,
  ERR_EXCEED,
  ERR_CROSS
};

export function canonicalBridgeKey(from, to) {
  return keyFor(from, to);
}
EOF

