import React, { useEffect, useMemo, useRef, useState } from 'react';
import { PUZZLES } from './data/puzzles.js';
import {
  canAddBridge,
  canonicalBridgeKey,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic.js';

const GRID = 40;
const W = 800;
const H = 600;

function isCtrlLike(e) {
  return e.ctrlKey || e.metaKey;
}

function findIslandAt(islands, x, y) {
  return islands.find((i) => i.x === x && i.y === y) || null;
}

function nextIslandInDirection(islands, from, dir) {
  const candidates = islands.filter((i) => i.id !== from.id);
  if (dir === 'left') {
    const sameRow = candidates.filter((i) => i.y === from.y && i.x < from.x);
    sameRow.sort((a, b) => b.x - a.x);
    return sameRow[0] || null;
  }
  if (dir === 'right') {
    const sameRow = candidates.filter((i) => i.y === from.y && i.x > from.x);
    sameRow.sort((a, b) => a.x - b.x);
    return sameRow[0] || null;
  }
  if (dir === 'up') {
    const sameCol = candidates.filter((i) => i.x === from.x && i.y < from.y);
    sameCol.sort((a, b) => b.y - a.y);
    return sameCol[0] || null;
  }
  if (dir === 'down') {
    const sameCol = candidates.filter((i) => i.x === from.x && i.y > from.y);
    sameCol.sort((a, b) => a.y - b.y);
    return sameCol[0] || null;
  }
  return null;
}

function cycleDelta(current) {
  // none -> single -> double -> none
  if (current === 0) return +1;
  if (current === 1) return +1;
  return -2;
