export default function App() {
  const [difficulty, setDifficulty] = useState('Easy');
  const puzzle = PUZZLES[difficulty];
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(islands[0]?.id ?? null);
  const [kbdFromId, setKbdFromId] = useState(null);
  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  useEffect(() => {
    // when puzzle changes: fully reset
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setCursorId(PUZZLES[difficulty].islands[0]?.id ?? null);
    setKbdFromId(null);
  }, [difficulty]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function applyBridge(from, to, delta) {
    const res = canAddBridge(islands, bridges, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return false;
    }
    setError(null);

    const k = canonicalBridgeKey(from, to);
    const current = bridges.get(k) ?? 0;
    const next = current + delta;

    const nb = new Map(bridges);
    if (next === 0) nb.delete(k);
    else nb.set(k, next);
    setBridges(nb);
    return true;
  }

  function toggleCycle(from, to) {
    const k = canonicalBridgeKey(from, to);
    const current = bridges.get(k) ?? 0;
    const delta = cycleDelta(current);
    applyBridge(from, to, delta);
  }

  function toggleRightClick(from, to) {
    const k = canonicalBridgeKey(from, to);
    const current = bridges.get(k) ?? 0;
    const delta = current > 0 ? -1 : +1;
    applyBridge(from, to, delta);
  }

  function onIslandClick(isl, e) {
    e.preventDefault();
    svgRef.current?.focus();

    setCursorId(isl.id);

    if (selectedId == null) {
      setSelectedId(isl.id);
      return;
    }
    if (selectedId === isl.id) return;

    const from = islands.find((i) => i.id === selectedId);
    const to = isl;
    toggleCycle(from, to);
    setSelectedId(null);
  }

  function onIslandContextMenu(isl, e) {
    e.preventDefault();
    svgRef.current?.focus();

    if (selectedId == null || selectedId === isl.id) {
      setSelectedId(isl.id);
      return;
    }
    const from = islands.find((i) => i.id === selectedId);
    toggleRightClick(from, isl);
    setSelectedId(null);
  }

  function onIslandCtrlClick(isl, e) {
    if (!isCtrlLike(e)) return;
    e.preventDefault();
    svgRef.current?.focus();

    if (selectedId == null || selectedId === isl.id) {
      setSelectedId(isl.id);
      return;
    }
    const from = islands.find((i) => i.id === selectedId);
    toggleRightClick(from, isl);
    setSelectedId(null);
  }

  function handleKeyDown(e) {
    if (!['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown', 'Enter', 'Escape'].includes(e.key)) return;
    e.preventDefault();

    const cursor = islands.find((i) => i.id === cursorId) || islands[0];
    if (!cursor) return;

    if (e.key === 'Escape') {
      setKbdFromId(null);
      setSelectedId(null);
      setError(null);
      return;
    }

    if (e.key.startsWith('Arrow')) {
      const dir =
        e.key === 'ArrowLeft' ? 'left' :
        e.key === 'ArrowRight' ? 'right' :
        e.key === 'ArrowUp' ? 'up' : 'down';

      const next = nextIslandInDirection(islands, cursor, dir);
      if (next) setCursorId(next.id);
      return;
    }

    if (e.key === 'Enter') {
      if (kbdFromId == null) {
        setKbdFromId(cursor.id);
        setSelectedId(cursor.id);
        return;
      }

      const from = islands.find((i) => i.id === kbdFromId);
      const to = cursor;
      if (!from || !to || from.id === to.id) return;

      const k = canonicalBridgeKey(from, to);
      const current = bridges.get(k) ?? 0;
      const delta = cycleDelta(current);
      const ok = applyBridge(from, to, delta);
      if (ok) {
        setKbdFromId(null);
        setSelectedId(null);
      }
    }
  }

  function reset() {
    setBridges(new Map());
    setSelectedId(null);
    setKbdFromId(null);
    setError(null);
    svgRef.current?.focus();
  }

  // render bridges
  const bridgeLines = [];
  const bridgeHitAreas = [];

  for (const [k, n] of bridges.entries()) {
    if (!n) continue;

    const [x1, y1, x2, y2] = k.split(',').map(Number);
    const ax = x1 * GRID;
    const ay = y1 * GRID;
    const bx = x2 * GRID;
    const by = y2 * GRID;

    const from = findIslandAt(islands, x1, y1);
    const to = findIslandAt(islands, x2, y2);

    // Transparent hit target so right-click / Ctrl+click on the bridge works.
    bridgeHitAreas.push(
      <line
        key={`hit-${k}`}
        x1={ax}
        y1={ay}
        x2={bx}
        y2={by}
        stroke="transparent"
        strokeWidth={18}
        strokeLinecap="round"
        onContextMenu={(e) => {
          e.preventDefault();
          svgRef.current?.focus();
          if (from && to) toggleRightClick(from, to);
        }}
        onClick={(e) => {
          if (!isCtrlLike(e)) return;
          e.preventDefault();
          svgRef.current?.focus();
          if (from && to) toggleRightClick(from, to);
        }}
      />
    );

    const isH = ay === by;
    const offset = 6;

    if (n === 1) {
      bridgeLines.push(
        <line
          key={`b-${k}-1`}
          x1={ax}
          y1={ay}
          x2={bx}
          y2={by}
          stroke="#00ff66"
          strokeWidth={4}
          strokeLinecap="round"
        />
      );
    } else if (n === 2) {
      const dx = isH ? 0 : offset;
      const dy = isH ? offset : 0;
      bridgeLines.push(
        <line
          key={`b-${k}-2a`}
          x1={ax - dx}
          y1={ay - dy}
          x2={bx - dx}
          y2={by - dy}
          stroke="#00ff66"
          strokeWidth={4}
          strokeLinecap="round"
        />
      );
      bridgeLines.push(
        <line
          key={`b-${k}-2b`}
          x1={ax + dx}
          y1={ay + dy}
          x2={bx + dx}
          y2={by + dy}
          stroke="#00ff66"
          strokeWidth={4}
          strokeLinecap="round"
        />
      );
    }
  }

  const cursor = islands.find((i) => i.id === cursorId) || islands[0];
  const cursorPx = cursor ? { x: cursor.x * GRID, y: cursor.y * GRID } : { x: 0, y: 0 };

  return (
    <div className="app">
      <div className="hud">
        <label>
          Puzzle
          <select value={difficulty} onChange={(e) => setDifficulty(e.target.value)}>
            <option value="Easy">Easy</option>
            <option value="Medium">Medium</option>
            <option value="Hard">Hard</option>
          </select>
        </label>
        <button onClick={reset}>Reset</button>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        ref={svgRef}
        width={W}
        height={H}
        viewBox={`0 0 ${W} ${H}`}
        style={{ display: 'block', position: 'absolute', top: 0, left: 0, background: '#000' }}
        tabIndex={0}
        onKeyDown={handleKeyDown}
      >
        {/* cursor (must not be a circle) */}
        {cursor ? (
          <rect
            x={cursorPx.x - 18}
            y={cursorPx.y - 18}
            width={36}
            height={36}
            fill="none"
            stroke="#00ff66"
            strokeWidth={3}
            strokeDasharray="6 4"
          />
        ) : null}

        {/* bridges under islands */}
        <g>{bridgeLines}</g>

        {/* interactive bridge hit areas */}
        <g>{bridgeHitAreas}</g>

        {/* islands */}
        <g>
          {islands.map((isl) => {
            const px = isl.x * GRID;
            const py = isl.y * GRID;
            const isSelected = selectedId === isl.id || kbdFromId === isl.id;
            const current = counts.get(isl.id) ?? 0;
            const satisfied = current === isl.value;

            return (
              <g key={isl.id}>
                <circle
                  cx={px}
                  cy={py}
                  r={16}
                  fill="#000"
                  stroke={isSelected ? '#00ff66' : 'rgba(0,255,102,0.7)'}
                  strokeWidth={isSelected ? 4 : 2}
                  onClick={(e) => {
                    onIslandCtrlClick(isl, e);
                    if (!isCtrlLike(e)) onIslandClick(isl, e);
                  }}
                  onContextMenu={(e) => onIslandContextMenu(isl, e)}
                />
                <text
                  x={px}
                  y={py + 6}
                  textAnchor="middle"
                  fontSize="16"
                  fill={satisfied ? '#00ff66' : 'rgba(0,255,102,0.9)'}
                >
                  {isl.value}
                </text>
              </g>
            );
          })}
        </g>
      </svg>
    </div>
  );
}
